import re
from vex_sdk import VexDataGuard

vex_guard = VexDataGuard(api_key='your-vex-key')

def anonymize_resume(resume_text):
    # Vex redacts protected characteristics
    cleaned = vex_guard.anonymize({
        'text': resume_text,
        'category': 'candidate_resume',
        'remove': ['name', 'gender', 'age', 'ethnicity', 'disability']
    })
    return cleaned['anonymized_text']

# Agent uses only anonymized data
screening_agent = Agent(
    role='Fairness-Aware Screener',
    goal='Score resumes using only job-relevant criteria',
    def preprocess_resume(self, resume):
        return anonymize_resume(resume)
)

task = Task(
    description='Score anonymized resumes for skills match',
    agent=screening_agent
)
